"use client";

import type { CSSProperties } from "react";

type CadenceProps = {
  text: string;
  lang?: string;
  className?: string;
  /** ms between glyphs — the tick of the incense clock. */
  step?: number;
  /** ms before the first glyph. */
  start?: number;
};

/**
 * Accessible split text. The real string lives in a visually-hidden span
 * (screen readers and find-in-page get it whole, once); the animated copy is
 * aria-hidden, one span per glyph, each carrying its own transition-delay as
 * a custom property. The glyphs' pre-reveal state is gated behind
 * `.kemuri-js` in styles.css, so without JavaScript — or under reduced
 * motion — the text is simply there.
 *
 * Split with Array.from so surrogate pairs survive; spaces become no-break
 * spaces so a glyph never collapses at a line edge. Lines that must wrap
 * should be split per line upstream — the poem and the wordmark both are.
 */
export default function Cadence({
  text,
  lang,
  className,
  step = 55,
  start = 0,
}: CadenceProps) {
  const glyphs = Array.from(text);
  return (
    <span className={`kemuri-cadence ${className ?? ""}`} lang={lang}>
      <span className="kemuri-sr">{text}</span>
      <span aria-hidden="true" className="kemuri-cadence__row">
        {glyphs.map((g, i) => (
          <span
            key={i}
            className="kemuri-cadence__g"
            style={{ "--kd": `${start + i * step}ms` } as CSSProperties}
          >
            {g === " " ? " " : g}
          </span>
        ))}
      </span>
    </span>
  );
}

"use client";

type Blend = {
  time: string;
  en: string;
  ja: string;
  notes: string;
  notesJa: string;
  price: string;
};

/**
 * What the atelier actually sells: hours. Five blends, each named for the
 * time of day it is meant to hold open. Notes read like weather reports
 * from inside a room, not perfume marketing.
 */
const BLENDS: Blend[] = [
  {
    time: "05:00",
    en: "First Ash",
    ja: "初灰",
    notes: "hinoki, cold river air, white pepper",
    notesJa: "檜、川の朝の冷気、白胡椒",
    price: "¥3,800",
  },
  {
    time: "09:00",
    en: "Paper Morning",
    ja: "紙の朝",
    notes: "kōzo paper, steamed rice, yesterday's rain",
    notesJa: "楮の紙、蒸した米、昨日の雨",
    price: "¥3,800",
  },
  {
    time: "14:00",
    en: "The Long Afternoon",
    ja: "長い午後",
    notes: "sandalwood, sun-dried tatami, a spoon of honey",
    notesJa: "白檀、日に干した畳、匙一杯の蜂蜜",
    price: "¥4,200",
  },
  {
    time: "19:00",
    en: "Lamp Hour",
    ja: "灯の刻",
    notes: "clove, old lacquer, temple dust",
    notesJa: "丁子、古い漆、御堂の埃",
    price: "¥4,600",
  },
  {
    time: "23:00",
    en: "Last Ember",
    ja: "残り火",
    notes: "agarwood, warm ash, the inside of a bell",
    notesJa: "沈香、ぬるい灰、鐘の内側",
    price: "¥5,800",
  },
];

/**
 * Section 04 — the hours. A quiet editorial ledger: hairline rules, one
 * ember numeral per row, and enough 間 (ma) that each blend gets a full
 * breath before the next. Nothing here is interactive on purpose — a menu
 * in this house is something you read slowly, not something you operate.
 */
export default function IncenseMenu() {
  return (
    <section className="kemuri-menu" aria-labelledby="kemuri-menu-title">
      <div className="kemuri-sechead" data-reveal="">
        <p className="kemuri-eyebrow" aria-hidden="true">
          04 — 香時間
        </p>
        <h2 className="kemuri-sechead__title" id="kemuri-menu-title">
          The hours{" "}
          <span lang="ja" className="kemuri-sechead__ja">
            香時間
          </span>
        </h2>
        <p className="kemuri-sechead__line">
          Each blend is one hour long. Burn it for the time, not the perfume.{" "}
          <span lang="ja" className="kemuri-sechead__lineja">
            どの香も、長さは一時間。香りのためでなく、時間のために焚く。
          </span>
        </p>
      </div>

      <ul className="kemuri-menu__list">
        {BLENDS.map((b) => (
          <li key={b.time} className="kemuri-menu__item" data-reveal="">
            <span className="kemuri-menu__time">{b.time}</span>
            <span className="kemuri-menu__names">
              <span className="kemuri-menu__en">{b.en}</span>
              <span lang="ja" className="kemuri-menu__ja">
                {b.ja}
              </span>
              <span className="kemuri-menu__notes">
                {b.notes}{" "}
                <span lang="ja" className="kemuri-menu__notesja">
                  {b.notesJa}
                </span>
              </span>
            </span>
            <span className="kemuri-menu__price">{b.price}</span>
          </li>
        ))}
      </ul>

      <p className="kemuri-menu__foot" data-reveal="">
        Sold by the hour, never by the gram.{" "}
        <span lang="ja">量り売りは時間で。グラムでは承っておりません。</span>
      </p>
    </section>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/** Displacement at the moment a plate enters view — pure weather. */
const SETTLE_FROM = 110;
/** How long the ink takes to settle (ms). */
const SETTLE_MS = 1900;

/**
 * Section 03 — the plates. Three sumi-e paintings.
 *
 * The art itself is now generated: ComfyUI sumi-e plates living at
 * /media/kemuri/plate-N-*.avif. But the signature interaction survives —
 * "ink settling out of water" — because each painting is embedded inside
 * an SVG via `<image>` and wrapped in the SAME per-plate
 * feTurbulence + feDisplacementMap filter the vector version used. SVG
 * filters operate on raster art exactly as on vector art, so while a plate
 * waits below the fold its displacement scale sits at 110 (the painting is
 * still weather), and as it enters the viewport a rAF loop eases the
 * `scale` attribute down to 0 and the painting settles into itself. Only
 * the displacement scale animates; the turbulence (baseFrequency, seed)
 * never changes, so the noise texture is computed once and each frame pays
 * displacement only.
 *
 * With JavaScript off the markup scale is already 0: the plates are simply
 * finished paintings. Under reduced motion they are never disturbed.
 *
 * Why SVG `<image>` and not a plain `<img>` with `filter: url()`: keeping
 * the art inside the SVG lets the displacement region, filter primitives,
 * and the no-JS `scale="0"` markup contract stay byte-for-byte identical
 * to the vector version — the rAF loop still calls `setAttribute` on the
 * same `<feDisplacementMap>` element it always did.
 */

type Plate = {
  /** number glyph shown in the caption */
  no: "壱" | "弐" | "参";
  /** latin numeral used in filter ids (kemuri-pN-settle) — kept ASCII so the
   *  url(#...) reference and any CSS selector stay encoding-safe. */
  id: 1 | 2 | 3;
  /** filename stem under /media/kemuri/, e.g. "plate-1-distant-mountains". */
  stem: string;
  /** bilingual alt — same role="img" contract the vector version kept. */
  alt: string;
  /** per-plate turbulence seed (kept from the vector plates — same weather). */
  seed: number;
  /** per-plate turbulence baseFrequency (kept from the vector plates). */
  freq: string;
  caption: {
    no: "壱" | "弐" | "参";
    ja: string;
    en: string;
  };
};

const PLATES: readonly Plate[] = [
  {
    no: "壱",
    id: 1,
    stem: "plate-1-distant-mountains",
    seed: 19,
    freq: "0.011 0.017",
    alt: "Sumi-e ink painting: three ranges of mountains dissolving into mist, a small gold sun low in the sky. 水墨画 — 霞に溶けていく三重の山なみ、低い空に小さな金の日。",
    caption: {
      no: "壱",
      ja: "遠山 — 山は近づいてこない。それが山のやさしさ。",
      en: "Distant mountains. They never come closer — that is their kindness.",
    },
  },
  {
    no: "弐",
    id: 2,
    stem: "plate-2-bare-branch",
    seed: 31,
    freq: "0.013 0.019",
    alt: "Sumi-e ink painting: a single bare branch reaching in from the right, one ember-colored bud at its tip. 水墨画 — 右から伸びる一本の枯枝、先端にひとつの熾色の芽。",
    caption: {
      no: "弐",
      ja: "枯枝 — 枝は何も持たない。持たないことを、うまくやる。",
      en: "A bare branch. It holds nothing, and holds it well.",
    },
  },
  {
    no: "参",
    id: 3,
    stem: "plate-3-censer-smoke",
    seed: 47,
    freq: "0.009 0.015",
    alt: "Sumi-e ink painting: a censer at the foot of the paper, one stick of incense, a ribbon of smoke written upward in a single stroke. 水墨画 — 紙の裾に香炉、一本の線香、ひと筆で上へ書かれた煙。",
    caption: {
      no: "参",
      ja: "一炷 — 墨と水と、辛抱。煙も同じ書き方で書かれる。",
      en: "One stick. Ink, water, patience — smoke is written the same way.",
    },
  },
];

export default function InkPlates() {
  const listRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();

  useEffect(() => {
    const list = listRef.current;
    if (!list) return;
    const figures = Array.from(
      list.querySelectorAll<HTMLElement>(".kemuri-plate"),
    );

    if (reduced || !("IntersectionObserver" in window)) {
      for (const fig of figures) fig.classList.add("is-inked");
      return;
    }

    const rafs = new Set<number>();
    // Raise the chaos only now that JS is known to be alive — before this
    // line (and forever, without JS) the paintings rest settled.
    const maps = new Map<HTMLElement, SVGFEDisplacementMapElement>();
    for (const fig of figures) {
      const fe = fig.querySelector("feDisplacementMap");
      if (!fe) continue;
      fe.setAttribute("scale", String(SETTLE_FROM));
      maps.set(fig, fe as SVGFEDisplacementMapElement);
    }

    const settle = (fig: HTMLElement) => {
      const fe = maps.get(fig);
      fig.classList.add("is-inked");
      if (!fe) return;
      const t0 = performance.now();
      const tick = (now: number) => {
        const p = Math.min((now - t0) / SETTLE_MS, 1);
        const ease = 1 - (1 - p) * (1 - p) * (1 - p); // cubic out — a sigh
        fe.setAttribute("scale", String(SETTLE_FROM * (1 - ease)));
        if (p < 1) rafs.add(requestAnimationFrame(tick));
      };
      rafs.add(requestAnimationFrame(tick));
    };

    const io = new IntersectionObserver(
      (hits) => {
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          io.unobserve(hit.target);
          settle(hit.target as HTMLElement);
        }
      },
      { threshold: 0.4 },
    );
    for (const fig of figures) io.observe(fig);

    return () => {
      io.disconnect();
      for (const id of rafs) cancelAnimationFrame(id);
    };
  }, [reduced]);

  return (
    <section className="kemuri-plates" aria-labelledby="kemuri-plates-title">
      <div className="kemuri-sechead" data-reveal="">
        <p className="kemuri-eyebrow" aria-hidden="true">
          03 — 三枚の図版
        </p>
        <h2 className="kemuri-sechead__title" id="kemuri-plates-title">
          Three plates{" "}
          <span lang="ja" className="kemuri-sechead__ja">
            三枚の図版
          </span>
        </h2>
        <p className="kemuri-sechead__line">
          The plates are not photographs. They are ink that remembers being
          water.{" "}
          <span lang="ja" className="kemuri-sechead__lineja">
            この図版は写真ではない。水だったことを覚えている墨だ。
          </span>
        </p>
      </div>

      <div className="kemuri-plates__row" ref={listRef}>
        {PLATES.map((plate) => (
          <figure className="kemuri-plate" key={plate.no}>
            <div className="kemuri-plate__paper">
              {/*
                The painting rides inside an SVG so the displacement-settle
                filter (feTurbulence + feDisplacementMap) can act on it.
                viewBox matches the vector plates' 440x560; the raster covers
                it via preserveAspectRatio="xMidYMid slice" (the paintings are
                3:4, near enough to fill the frame with a hair's crop).
                The filter region is padded -14%/128% so displaced pixels at
                the edge do not clamp — same as before.
              */}
              <svg
                className="kemuri-plate__art"
                viewBox="0 0 440 560"
                role="img"
                aria-label={plate.alt}
              >
                <defs>
                  <filter
                    id={`kemuri-p${plate.id}-settle`}
                    x="-14%"
                    y="-14%"
                    width="128%"
                    height="128%"
                  >
                    <feTurbulence
                      type="fractalNoise"
                      baseFrequency={plate.freq}
                      numOctaves="2"
                      seed={plate.seed}
                      result="w"
                    />
                    <feDisplacementMap
                      in="SourceGraphic"
                      in2="w"
                      scale="0"
                      xChannelSelector="R"
                      yChannelSelector="G"
                    />
                  </filter>
                </defs>
                <g filter={`url(#kemuri-p${plate.id}-settle)`}>
                  <image
                    href={`/media/kemuri/${plate.stem}.avif`}
                    x="0"
                    y="0"
                    width="440"
                    height="560"
                    preserveAspectRatio="xMidYMid slice"
                    // AVIF is decoded by every modern browser's SVG <image>;
                    // the WebP fallback for older engines is documented in
                    // PROMPT.md image-recipe. The plate's paper frame,
                    // hairline mount, and caption live in CSS unchanged.
                  />
                </g>
              </svg>
            </div>
            <figcaption className="kemuri-plate__caption">
              <span className="kemuri-plate__no" aria-hidden="true">
                {plate.caption.no}
              </span>
              <span lang="ja" className="kemuri-plate__ja">
                {plate.caption.ja}
              </span>
              <span className="kemuri-plate__en">{plate.caption.en}</span>
            </figcaption>
          </figure>
        ))}
      </div>
    </section>
  );
}

"use client";

import { useEffect, useState } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/** The seal holds this long before the paper lifts (ms). */
const HOLD_MS = 1450;
/** How long the lift itself takes — must match --kemuri-loader-lift in CSS. */
const LIFT_MS = 650;

/**
 * The entry: a beat of blank washi, an ember seal pressed into it, then the
 * paper lifts and the censer is already burning underneath. It exists to buy
 * the smoke its first breath — nothing more — so it is aggressively
 * skippable: any key, tap, wheel, or scroll lifts it at once, a hard timeout
 * lifts it regardless, and under reduced motion (or with JavaScript off) it
 * never appears at all. `onDone` fires when the lift *starts*, so the hero's
 * glyph cadence overlaps the paper leaving.
 */
export default function Loader({ onDone }: { onDone: () => void }) {
  const reduced = usePrefersReducedMotion();
  const [phase, setPhase] = useState<"idle" | "held" | "lifting" | "gone">(
    "idle",
  );

  useEffect(() => {
    // Every state change is deferred behind a timer or listener — nothing
    // sets state synchronously in the effect body, so mounting never
    // cascades. Under reduced motion the overlay simply never appears.
    if (reduced) {
      const id = window.setTimeout(() => {
        setPhase("gone");
        onDone();
      }, 0);
      return () => window.clearTimeout(id);
    }

    let lifted = false;
    let liftTimer = 0;
    const lift = () => {
      if (lifted) return;
      lifted = true;
      setPhase("lifting");
      onDone();
      liftTimer = window.setTimeout(() => setPhase("gone"), LIFT_MS);
    };

    const showTimer = window.setTimeout(() => {
      setPhase((p) => (p === "idle" ? "held" : p));
    }, 10);
    const holdTimer = window.setTimeout(lift, HOLD_MS);
    const opts = { passive: true } as const;
    window.addEventListener("keydown", lift);
    window.addEventListener("pointerdown", lift, opts);
    window.addEventListener("wheel", lift, opts);
    window.addEventListener("touchstart", lift, opts);
    window.addEventListener("scroll", lift, opts);

    return () => {
      window.clearTimeout(showTimer);
      window.clearTimeout(holdTimer);
      window.clearTimeout(liftTimer);
      window.removeEventListener("keydown", lift);
      window.removeEventListener("pointerdown", lift);
      window.removeEventListener("wheel", lift);
      window.removeEventListener("touchstart", lift);
      window.removeEventListener("scroll", lift);
    };
  }, [reduced, onDone]);

  if (phase === "idle" || phase === "gone") return null;

  return (
    <div
      className={`kemuri-loader ${phase === "lifting" ? "is-lifting" : ""}`}
      aria-hidden="true"
    >
      <div className="kemuri-loader__seal">
        <svg viewBox="0 0 96 96" width={96} height={96} focusable="false">
          <rect
            x="6"
            y="6"
            width="84"
            height="84"
            rx="4"
            fill="#c96f2e"
          />
          <rect
            x="12.5"
            y="12.5"
            width="71"
            height="71"
            rx="2"
            fill="none"
            stroke="#efe7d8"
            strokeOpacity="0.55"
            strokeWidth="1"
          />
          <text
            className="kemuri-sealglyph"
            x="48"
            y="66"
            textAnchor="middle"
            fontSize="46"
            fill="#efe7d8"
          >
            煙
          </text>
        </svg>
        <p className="kemuri-loader__word">
          an hour of stillness <span lang="ja">静けさを、一時間</span>
        </p>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";
import { useScrollVelocity } from "../hooks/useScrollVelocity";

/* -- rendering ------------------------------------------------------------ */
/** Backing-store resolution cap. */
const MAX_DPR = 2;
/** Skip frames that arrive faster than ~64fps (high-refresh displays). */
const FRAME_MS = 15.5;
/** One particle per this many CSS px² of stage, clamped below. */
const AREA_PER_PARTICLE = 1900;
const MIN_PARTICLES = 260;
const MAX_PARTICLES = 820;
/** Particle layout in the Float32Array: x, y, vx, vy, age, life, s0. */
const STRIDE = 7;

/* -- the curl field ------------------------------------------------------- */
/** Feature sizes of the two potential octaves (px⁻¹): broad coils, fine curls. */
const EDDY_LARGE = 1 / 150;
const EDDY_SMALL = 1 / 56;
/** The noise field itself drifts upward (px/s), so eddies travel with the smoke. */
const FIELD_RISE = 26;
/** Curl gain — converts potential slope into px/s of swirl. */
const SWIRL = 1500;
/** Finite-difference epsilon for the curl (px). */
const CURL_EPS = 2.5;

/* -- plume physics --------------------------------------------------------- */
/** Base buoyancy (px/s). */
const RISE = 46;
/** Velocity relaxation rate (s⁻¹) — smoke has inertia, not obedience. */
const VEL_RELAX = 2.4;
/** Seconds of life: min + random spread. */
const LIFE_MIN = 6.5;
const LIFE_SPREAD = 4.5;

/* -- outside influences ---------------------------------------------------- */
/** Pointer pull: px/s per px of horizontal distance, capped hard. */
const POINTER_WIND = 1.1;
const POINTER_CAP = 54;
/** Pointer energy lerps — quick to notice a hand, slow to forget it. */
const POINTER_ATTACK = 0.055;
const POINTER_RELEASE = 0.018;
/** Pointer silence before the autonomous breeze takes back over (ms). */
const IDLE_MS = 2600;
/** Scroll lag: px/s of downward drag per px/ms of scroll velocity, capped. */
const SCROLL_WIND = 210;
const SCROLL_CAP = 190;
/** Scroll smoothing rate (s⁻¹) and staleness window (ms). */
const SCROLL_SMOOTH = 6.5;
const SCROLL_STALE_MS = 140;

/* -- warmup ----------------------------------------------------------------- */
/** Pre-advection so the plume is already mid-air on first paint. */
const WARMUP_STEPS = 120;
const WARMUP_DT = 0.085;

/** Where the plume is born, relative to the stage (must match the censer CSS:
 *  the svg is 160px wide, anchored bottom: 44px, centered; the stick tip sits
 *  at (86, 26) in its 160×120 viewBox). */
const MOUTH_DX = 6;
const MOUTH_UP = 138;

function clamp(v: number, lo: number, hi: number): number {
  return v < lo ? lo : v > hi ? hi : v;
}

function smoothstep(a: number, b: number, x: number): number {
  const s = clamp((x - a) / (b - a), 0, 1);
  return s * s * (3 - 2 * s);
}

/** Deterministic PRNG — the smoke coils the same way every visit. */
function mulberry32(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (s + 0x6d2b79f5) | 0;
    let z = Math.imul(s ^ (s >>> 15), 1 | s);
    z = (z + Math.imul(z ^ (z >>> 7), 61 | z)) ^ z;
    return ((z ^ (z >>> 14)) >>> 0) / 4294967296;
  };
}

/** 256-entry permutation for the lattice hash. Seeded 1927 — est. of the house. */
function buildPerm(): Uint8Array {
  const rand = mulberry32(1927);
  const p = new Uint8Array(256);
  for (let i = 0; i < 256; i++) p[i] = i;
  for (let i = 255; i > 0; i--) {
    const j = (rand() * (i + 1)) | 0;
    const t = p[i];
    p[i] = p[j];
    p[j] = t;
  }
  return p;
}

const PERM = buildPerm();

/** Lattice hash → [0, 1). */
function latHash(ix: number, iy: number): number {
  return PERM[(ix + PERM[iy & 255]) & 255] / 255;
}

/** Smooth-stepped bilinear value noise over the integer lattice. */
function valueNoise(x: number, y: number): number {
  const ix = Math.floor(x);
  const iy = Math.floor(y);
  let fx = x - ix;
  let fy = y - iy;
  fx = fx * fx * (3 - 2 * fx);
  fy = fy * fy * (3 - 2 * fy);
  const a = latHash(ix, iy);
  const b = latHash(ix + 1, iy);
  const c = latHash(ix, iy + 1);
  const d = latHash(ix + 1, iy + 1);
  return a + (b - a) * fx + (c - a) * fy + (a - b - c + d) * fx * fy;
}

/**
 * The scalar potential ψ. Two octaves of value noise, and the whole field
 * drifts upward over time (y is offset by t·FIELD_RISE), so the eddies rise
 * with the smoke instead of the smoke swimming through frozen turbulence.
 */
function psi(x: number, y: number, t: number): number {
  const yr = y + t * FIELD_RISE;
  return (
    valueNoise(x * EDDY_LARGE, yr * EDDY_LARGE) -
    0.5 +
    (valueNoise(x * EDDY_SMALL + 37.2, yr * (EDDY_SMALL * 1.35) + 11.8) - 0.5) *
      0.45
  );
}

/** A soft radial sprite: color core fading to transparent. */
function makeSprite(r: number, g: number, b: number, core: number): HTMLCanvasElement {
  const size = 64;
  const c = document.createElement("canvas");
  c.width = size;
  c.height = size;
  const cx = c.getContext("2d");
  if (cx) {
    const grad = cx.createRadialGradient(32, 32, 0, 32, 32, 32);
    grad.addColorStop(0, `rgba(${r},${g},${b},${core})`);
    grad.addColorStop(0.4, `rgba(${r},${g},${b},${core * 0.42})`);
    grad.addColorStop(1, `rgba(${r},${g},${b},0)`);
    cx.fillStyle = grad;
    cx.fillRect(0, 0, size, size);
  }
  return c;
}

/**
 * The signature moment. A censer breathes one ribbon of smoke, advected
 * through a divergence-free curl-noise field: velocity = (∂ψ/∂y, −∂ψ/∂x),
 * so the flow can coil forever but never compress or tear — which is what
 * separates smoke from confetti. The ribbon bends downward under lerped
 * scroll velocity (it lags the page like real smoke lags a moved cup) and
 * leans toward a fine pointer, capped so it stays weather, never a cursor
 * toy. On touch, or when the hand goes quiet, an autonomous breeze keeps it
 * alive. Reduced motion pre-advects the system and paints one composed
 * still. The loop pauses offscreen and when the tab hides.
 */
export default function SmokeCanvas() {
  const stageRef = useRef<HTMLDivElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const scrollRef = useScrollVelocity();

  useEffect(() => {
    const stage = stageRef.current;
    const canvas = canvasRef.current;
    if (!stage || !canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const fine = window.matchMedia(
      "(hover: hover) and (pointer: fine)",
    ).matches;
    const rand = mulberry32(19270701);

    // Sprites: young smoke is ink-dense, old smoke is pale; the ember is
    // the one warm thing on the page. Every color is a sheet token:
    // ink-soft #4f4a43 · smoke #8a8178 · ember #c96f2e.
    const inkSprite = makeSprite(79, 74, 67, 0.62);
    const smokeSprite = makeSprite(138, 129, 120, 0.5);
    const emberSprite = makeSprite(201, 111, 46, 0.85);

    let W = 0;
    let H = 0;
    let mouthX = 0;
    let mouthY = 0;
    let docTop = 0;
    let docLeft = 0;
    let count = 0;
    let parts = new Float32Array(0);

    let raf = 0;
    let running = false;
    let inView = false;
    let last = 0;
    let t = 0; // simulation clock, seconds

    const ptr = { x: 0, y: 0, e: 0 };
    const target = { x: 0, y: 0, e: 0 };
    let lastMove = -1e9;
    let scrollLag = 0; // smoothed, px/s

    const spawn = (i: number, warm: boolean) => {
      const o = i * STRIDE;
      // Sum of two uniforms ≈ triangular — a soft-shouldered plume base.
      parts[o] = mouthX + (rand() + rand() - 1) * 8;
      parts[o + 1] = mouthY + rand() * 5;
      parts[o + 2] = 0;
      parts[o + 3] = -RISE * 0.6;
      parts[o + 5] = LIFE_MIN + rand() * LIFE_SPREAD;
      parts[o + 4] = warm ? rand() * parts[o + 5] : 0;
      parts[o + 6] = 5 + rand() * 6;
    };

    const step = (dt: number) => {
      t += dt;
      const relax = 1 - Math.exp(-dt * VEL_RELAX);
      // The breeze: two slow sines with unrelated periods (~30s and ~13s).
      const breeze =
        22 * Math.sin(t * 0.21) + 12 * Math.sin(t * 0.47 + 1.9);

      for (let i = 0; i < count; i++) {
        const o = i * STRIDE;
        let x = parts[o];
        let y = parts[o + 1];
        const age = parts[o + 4] + dt;
        const life = parts[o + 5];

        if (age >= life || y < -50 || x < -90 || x > W + 90) {
          spawn(i, false);
          parts[i * STRIDE + 4] = 0;
          continue;
        }

        // Divergence-free flow: velocity = (∂ψ/∂y, −∂ψ/∂x).
        const cx =
          (psi(x, y + CURL_EPS, t) - psi(x, y - CURL_EPS, t)) / (2 * CURL_EPS);
        const cy =
          -(psi(x + CURL_EPS, y, t) - psi(x - CURL_EPS, y, t)) /
          (2 * CURL_EPS);

        const h01 = clamp(1 - y / H, 0, 1);
        const hw = 0.15 + 0.85 * h01 * h01; // the base stays anchored

        let wind = breeze;
        if (ptr.e > 0.01) {
          const pull = clamp(
            (ptr.x - x) * POINTER_WIND,
            -POINTER_CAP,
            POINTER_CAP,
          );
          const reach = Math.exp(
            -((y - ptr.y) * (y - ptr.y)) / (H * H * 0.09),
          );
          wind += pull * ptr.e * reach;
        }

        const tvx = cx * SWIRL + wind * hw;
        const tvy =
          -RISE * (0.78 + 0.04 * parts[o + 6]) +
          cy * SWIRL * 0.65 +
          scrollLag * (0.2 + 0.8 * h01);

        const vx = parts[o + 2] + (tvx - parts[o + 2]) * relax;
        const vy = parts[o + 3] + (tvy - parts[o + 3]) * relax;
        x += vx * dt;
        y += vy * dt;

        parts[o] = x;
        parts[o + 1] = y;
        parts[o + 2] = vx;
        parts[o + 3] = vy;
        parts[o + 4] = age;
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, W, H);

      // The censer's ember, breathing under the plume.
      const pulse = reduced ? 0.55 : 0.45 + 0.16 * Math.sin(t * 1.7);
      ctx.globalAlpha = pulse;
      ctx.drawImage(emberSprite, mouthX - 15, mouthY - 13, 30, 30);

      for (let i = 0; i < count; i++) {
        const o = i * STRIDE;
        const age = parts[o + 4];
        const life = parts[o + 5];
        const a01 = age / life;
        const x = parts[o];
        const y = parts[o + 1];

        const fadeIn = age > 0.6 ? 1 : age / 0.6;
        const fadeOut = (1 - a01) * Math.sqrt(1 - a01);
        const topFade = clamp(y / (H * 0.14), 0, 1);
        const alpha = 0.088 * fadeIn * fadeOut * topFade;
        if (alpha < 0.004) continue;

        const size = parts[o + 6] * (1 + a01 * 4.6) * 3.2;
        const half = size / 2;
        // Ink → pale-smoke crossfade as the ribbon disperses.
        const m = smoothstep(0.12, 0.48, a01);
        if (m < 1) {
          ctx.globalAlpha = alpha * (1 - m) * 1.2;
          ctx.drawImage(inkSprite, x - half, y - half, size, size);
        }
        if (m > 0) {
          ctx.globalAlpha = alpha * m;
          ctx.drawImage(smokeSprite, x - half, y - half, size, size);
        }
        // A dying ember glint rides the first half-second of each particle.
        if (age < 0.55) {
          ctx.globalAlpha = (1 - age / 0.55) * 0.4 * fadeIn;
          const es = parts[o + 6] * 1.6;
          ctx.drawImage(emberSprite, x - es / 2, y - es / 2, es, es);
        }
      }
      ctx.globalAlpha = 1;
    };

    const frame = (now: number) => {
      raf = requestAnimationFrame(frame);
      if (now - last < FRAME_MS) return;
      const dt = Math.min(now - last, 48) / 1000;
      last = now;

      // Scroll velocity: stale samples mean the page has stopped.
      const s = scrollRef.current;
      const eff = now - s.t < SCROLL_STALE_MS ? s.v : 0;
      const lagTarget = clamp(eff * SCROLL_WIND, -SCROLL_CAP, SCROLL_CAP);
      scrollLag += (lagTarget - scrollLag) * (1 - Math.exp(-dt * SCROLL_SMOOTH));

      // Autonomous drift when there is no hand to follow.
      if (!fine || now - lastMove > IDLE_MS) {
        target.x = mouthX + W * 0.16 * Math.sin(t * 0.13);
        target.y = H * (0.45 + 0.1 * Math.sin(t * 0.29 + 1.1));
        target.e = 0.32 + 0.1 * Math.sin(t * 0.37);
      }
      const k = clamp(dt * 60, 0, 3); // frame-rate normalization
      ptr.x += (target.x - ptr.x) * 0.085 * k;
      ptr.y += (target.y - ptr.y) * 0.085 * k;
      const ek = target.e > ptr.e ? POINTER_ATTACK : POINTER_RELEASE;
      ptr.e += (target.e - ptr.e) * ek * k;

      step(dt);
      draw();
    };

    const start = () => {
      if (running || reduced) return;
      running = true;
      last = performance.now();
      raf = requestAnimationFrame(frame);
    };
    const stop = () => {
      running = false;
      cancelAnimationFrame(raf);
    };

    const warmup = () => {
      for (let i = 0; i < count; i++) spawn(i, true);
      for (let i = 0; i < WARMUP_STEPS; i++) step(WARMUP_DT);
    };

    const resize = () => {
      const rect = stage.getBoundingClientRect();
      if (rect.width < 4 || rect.height < 4) return;
      const dpr = Math.min(window.devicePixelRatio || 1, MAX_DPR);
      W = rect.width;
      H = rect.height;
      docTop = rect.top + window.scrollY;
      docLeft = rect.left + window.scrollX;
      canvas.width = Math.round(W * dpr);
      canvas.height = Math.round(H * dpr);
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      mouthX = W / 2 + MOUTH_DX;
      mouthY = H - MOUTH_UP;

      const wanted = clamp(
        Math.round((W * H) / AREA_PER_PARTICLE),
        MIN_PARTICLES,
        MAX_PARTICLES,
      );
      if (wanted !== count) {
        count = wanted;
        parts = new Float32Array(count * STRIDE);
        ptr.x = mouthX;
        ptr.y = H * 0.5;
        target.x = mouthX;
        target.y = H * 0.5;
        warmup();
      }
      if (!running) draw();
    };

    const onPointerMove = (ev: PointerEvent) => {
      if (ev.pointerType !== "mouse" && ev.pointerType !== "pen") return;
      const x = ev.clientX - (docLeft - window.scrollX);
      const y = ev.clientY - (docTop - window.scrollY);
      if (x < -40 || x > W + 40 || y < -40 || y > H + 40) return;
      target.x = x;
      target.y = y;
      target.e = 1;
      lastMove = performance.now();
    };

    const onVisibility = () => {
      if (document.hidden) stop();
      else if (inView) start();
    };

    resize();

    const ro = new ResizeObserver(() => {
      resize();
    });
    ro.observe(stage);

    let io: IntersectionObserver | null = null;
    if (!reduced) {
      if (fine) window.addEventListener("pointermove", onPointerMove);
      io = new IntersectionObserver(
        (hits) => {
          inView = hits[hits.length - 1].isIntersecting;
          if (inView && !document.hidden) start();
          else stop();
        },
        { rootMargin: "80px 0px" },
      );
      io.observe(stage);
      document.addEventListener("visibilitychange", onVisibility);
    }

    return () => {
      stop();
      ro.disconnect();
      if (io) io.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
      window.removeEventListener("pointermove", onPointerMove);
    };
  }, [reduced, scrollRef]);

  return (
    <div
      ref={stageRef}
      className="kemuri-smoke"
      role="img"
      aria-label="A single ribbon of incense smoke rises from a bronze censer, coiling and untying itself as it climbs, leaning gently toward your hand. 香炉から一筋の煙が立ちのぼり、ほどけては結び直しながら、そっと手のほうへ傾く。"
    >
      <canvas ref={canvasRef} className="kemuri-smoke__canvas" aria-hidden="true" />
    </div>
  );
}

import { EB_Garamond, Zen_Old_Mincho } from "next/font/google";

/**
 * The two voices of the atelier:
 * EB Garamond — the Latin voice; the wordmark, the hours, the English koans.
 *   400 for prose, 500 for the few display moments, italic for translation —
 *   the register of someone writing slowly with a good pen.
 * Zen Old Mincho — every Japanese glyph on the page: the vertical poem, the
 *   blend names, the sign-off. An old-style mincho whose strokes still
 *   remember the brush, which is the entire premise.
 *
 * styles.css consumes these as var(--font-garamond) / var(--font-mincho);
 * page.tsx applies the .variable classes on the entry root. The family stack
 * runs Garamond first, so kanji and kana fall through it into the mincho
 * with no extra markup.
 */
export const ebGaramond = EB_Garamond({
  weight: ["400", "500"],
  style: ["normal", "italic"],
  subsets: ["latin"],
  variable: "--font-garamond",
  display: "swap",
});

export const zenOldMincho = Zen_Old_Mincho({
  weight: ["400", "500"],
  subsets: ["latin"],
  variable: "--font-mincho",
  display: "swap",
});

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. The pre-reveal state (opacity/translate,
 * or the poem's per-glyph cadence) lives in styles.css and is gated behind
 * the `.kemuri-js` root class, so every word is plainly visible when
 * JavaScript never runs.
 *
 * Two flavors:
 *   data-reveal          — the element itself fades and rises (0.9s), with a
 *                          90ms stagger between elements of the same
 *                          observer batch, so a screenful never moves as one
 *                          slab.
 *   data-reveal="scene"  — the element does not animate itself; it only
 *                          receives `is-visible` so its descendants (poem
 *                          glyphs, plate captions) can run their own
 *                          choreographed delays.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          if (el.dataset.reveal !== "scene") {
            el.style.transitionDelay = `${batch * 90}ms`;
            batch += 1;
          }
          el.classList.add("is-visible");
          io.unobserve(el);
        }
      },
      { threshold: 0.18, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useEffect, useRef } from "react";

export type ScrollVelocitySample = {
  /** Signed scroll velocity in px/ms (positive = scrolling down), clamped. */
  v: number;
  /** performance.now() timestamp of the sample. */
  t: number;
};

/** Instantaneous velocity clamp — flicks beyond this read the same. */
const V_CLAMP = 6;

/**
 * Tracks raw scroll velocity into a ref, without ever re-rendering React.
 *
 * The hook stays deliberately dumb: it records the *instantaneous* velocity
 * and its timestamp on every scroll event, and nothing else. Smoothing (the
 * lerp that makes the smoke bend rather than jerk) belongs to the consumer's
 * rAF loop, where it can be frame-rate normalized — see SmokeCanvas, which
 * treats a sample older than ~140ms as "the page has stopped".
 */
export function useScrollVelocity() {
  const sample = useRef<ScrollVelocitySample>({ v: 0, t: 0 });

  useEffect(() => {
    let lastY = window.scrollY;
    let lastT = performance.now();

    const onScroll = () => {
      const now = performance.now();
      const dt = now - lastT;
      const dy = window.scrollY - lastY;
      lastY = window.scrollY;
      lastT = now;
      if (dt <= 0) return;
      const v = dy / Math.max(dt, 4);
      sample.current = {
        v: v > V_CLAMP ? V_CLAMP : v < -V_CLAMP ? -V_CLAMP : v,
        t: now,
      };
    };

    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return sample;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import "./styles.css";
import { ebGaramond, zenOldMincho } from "./fonts";
import Loader from "./components/Loader";
import Hero from "./components/Hero";
import Poem from "./components/Poem";
import InkPlates from "./components/InkPlates";
import IncenseMenu from "./components/IncenseMenu";
import CTAFooter from "./components/CTAFooter";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";

/**
 * KEMURI — incense atelier, Kyoto, est. 1927. The house sells an hour of
 * stillness; the page is that hour, rehearsed. Washi and sumi, ember and
 * gold leaf; EB Garamond speaking English slowly, Zen Old Mincho holding
 * the Japanese upright. One censer, one ribbon of curl-noise smoke, three
 * sumi-e plates that settle out of water, a ledger of hours, and a dark
 * room at the end. The smoke is canvas, the washi grain and censer are
 * SVG, and the three plates are generated sumi-e paintings embedded as
 * SVG <image> so the ink-settle displacement filter still owns them.
 *
 * `.kemuri-js` is added imperatively on mount (it never changes, so it is a
 * signal to CSS that JS is alive, not React state): every pre-reveal style
 * is gated behind it, and with JavaScript off the full page simply stands
 * finished. The `entered` state is React's, because the hero's cadence
 * genuinely depends on the loader lifting.
 */
export default function KemuriPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLDivElement>(reduced);
  const [entered, setEntered] = useState(false);
  const handleEntered = useCallback(() => setEntered(true), []);

  useEffect(() => {
    rootRef.current?.classList.add("kemuri-js");
    window.parent?.postMessage({ type: "oneshot:ready", slug: "kemuri" }, "*");
  }, []);

  return (
    <div
      id="kemuri-top"
      ref={rootRef}
      className={`${ebGaramond.variable} ${zenOldMincho.variable} kemuri-root`}
    >
      <Loader onDone={handleEntered} />

      <div ref={revealRef} className="kemuri-sheet">
        <Hero entered={entered} />
        <main>
          <Poem />
          <InkPlates />
          <IncenseMenu />
        </main>
        <CTAFooter />
      </div>

      {/* Washi grain: one static feTurbulence pass over everything.
          Fibers, not film grain — it never animates. */}
      <svg className="kemuri-grain" aria-hidden="true" focusable="false">
        <filter id="kemuri-grain-f">
          <feTurbulence
            type="fractalNoise"
            baseFrequency="0.55"
            numOctaves="2"
            seed="9"
            stitchTiles="stitch"
          />
          <feColorMatrix
            type="matrix"
            values="0 0 0 0 0.11  0 0 0 0 0.094  0 0 0 0 0.078  0 0 0 0.05 0"
          />
        </filter>
        <rect width="100%" height="100%" filter="url(#kemuri-grain-f)" />
      </svg>
    </div>
  );
}

/* ==========================================================================
   KEMURI — incense atelier, Kyoto, est. 1927
   washi-sumi-e · washi / sumi / ember / gold leaf · an hour of stillness
   Scoped by convention to .kemuri-root; classes prefixed kemuri-.
   ========================================================================== */

.kemuri-root {
  /* -- palette ----------------------------------------------------------- */
  --kemuri-washi: #efe7d8;      /* the paper — every hour is burned on it */
  --kemuri-washi-aged: #e3d7c0; /* plate paper, hover washes, aged edges */
  --kemuri-sumi: #1c1814;       /* the ink — 14.4:1 on washi */
  --kemuri-ink-soft: #4f4a43;   /* sumi thinned with water — 7.1:1, secondary text */
  --kemuri-smoke: #8a8178;      /* the smoke — 3.1:1, large or decorative only */
  --kemuri-ember: #c96f2e;      /* the coal — 2.9:1 on washi: decorative there,
                                   4.9:1 on sumi: allowed to speak in the dark */
  --kemuri-ember-deep: #a04f16; /* banked ember — 4.7:1 on washi, functional accent */
  --kemuri-gold: #b08d4a;       /* gold leaf — 2.5:1: hairlines and the sun, never text */
  --kemuri-washi-dim: rgba(239, 231, 216, 0.72); /* ≈ #b4ada1 on sumi — 7.9:1 */
  --kemuri-hairline: rgba(28, 24, 20, 0.16);
  --kemuri-hairline-strong: rgba(28, 24, 20, 0.3);

  /* -- type ---------------------------------------------------------------- */
  --kemuri-font-latin: var(--font-garamond), "EB Garamond", serif;
  --kemuri-font-jp: var(--font-mincho), "Zen Old Mincho", serif;
  /* kanji and kana fall through Garamond into the mincho with no markup */
  --kemuri-font-stack: var(--font-garamond), var(--font-mincho), serif;

  /* -- motion ---------------------------------------------------------------
     Two easings on the whole page: smoke (rises fast, settles long) for every
     entrance, ink (deliberate, weighted) for the loader lift and button fill. */
  --kemuri-ease-smoke: cubic-bezier(0.22, 1, 0.36, 1);
  --kemuri-ease-ink: cubic-bezier(0.65, 0, 0.35, 1);
  --kemuri-reveal-ms: 900ms;
  --kemuri-glyph-ms: 1150ms;
  --kemuri-loader-lift: 650ms;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--kemuri-washi);
  color: var(--kemuri-sumi);
  font-family: var(--kemuri-font-stack);
  font-weight: 400;
  font-size: clamp(17px, 1vw + 12px, 20px);
  line-height: 1.75;
  overflow-x: hidden;
  overflow-x: clip;
}

/* Japanese is first-class: Zen Old Mincho, opened up a little — vertical or
   horizontal, the kana get room to breathe. */
.kemuri-root :lang(ja) {
  font-family: var(--kemuri-font-jp);
  letter-spacing: 0.06em;
}

/* Ember selection, scoped to the entry root. Banked ember, so the selected
   washi text stays AA (4.7:1). */
.kemuri-root ::selection {
  background: var(--kemuri-ember-deep);
  color: var(--kemuri-washi);
  text-shadow: none;
}

/* Keyboard focus: an ember ring, held one paper-thickness away. */
.kemuri-root :focus-visible {
  outline: 2px solid var(--kemuri-ember-deep);
  outline-offset: 4px;
  border-radius: 1px;
}

.kemuri-cta :focus-visible {
  outline-color: var(--kemuri-ember);
}

/* Visually hidden, present for screen readers and find-in-page. */
.kemuri-sr {
  position: absolute;
  width: 1px;
  height: 1px;
  margin: -1px;
  padding: 0;
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
  border: 0;
}

.kemuri-sheet {
  position: relative;
}

/* Kanji cut into the seals — always the mincho, wherever the seal appears. */
.kemuri-sealglyph {
  font-family: var(--kemuri-font-jp);
}

/* ==========================================================================
   Washi — the paper itself
   One static feTurbulence grain pass (multiplied, ≤5% ink) and a faint gold
   age-vignette. Neither ever animates; the paper is old, not alive.
   ========================================================================== */

.kemuri-grain {
  position: fixed;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: 40;
  pointer-events: none;
  mix-blend-mode: multiply;
  opacity: 0.75;
}

.kemuri-root::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 39;
  pointer-events: none;
  background:
    radial-gradient(
      120% 95% at 50% 42%,
      transparent 55%,
      rgba(176, 141, 74, 0.09) 100%
    ),
    repeating-linear-gradient(
      0deg,
      rgba(28, 24, 20, 0.012) 0 2px,
      transparent 2px 7px
    );
}

/* ==========================================================================
   Reveal primitives
   Everything pre-reveal lives under .kemuri-js: with JavaScript off the page
   stands finished. data-reveal elements fade-rise; data-reveal="scene"
   containers never move themselves — they only hand `is-visible` to the
   choreography inside (poem glyphs, English lines).
   ========================================================================== */

.kemuri-js [data-reveal]:not([data-reveal="scene"]) {
  opacity: 0;
  transform: translateY(18px);
  transition:
    opacity var(--kemuri-reveal-ms) var(--kemuri-ease-smoke),
    transform var(--kemuri-reveal-ms) var(--kemuri-ease-smoke);
}

.kemuri-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* Split glyphs — the hero wordmark and the poem share one cadence system.
   Each glyph carries its own delay as --kd; only opacity/transform/filter
   ever animate. */
.kemuri-hero__glyph,
.kemuri-cadence__g {
  display: inline-block;
  transition:
    opacity var(--kemuri-glyph-ms) var(--kemuri-ease-smoke) var(--kd, 0ms),
    transform var(--kemuri-glyph-ms) var(--kemuri-ease-smoke) var(--kd, 0ms),
    filter var(--kemuri-glyph-ms) var(--kemuri-ease-smoke) var(--kd, 0ms);
}

.kemuri-js .kemuri-hero:not(.is-entered) .kemuri-hero__glyph,
.kemuri-js .kemuri-hero:not(.is-entered) .kemuri-cadence__g,
.kemuri-js [data-reveal="scene"]:not(.is-visible) .kemuri-cadence__g {
  opacity: 0;
  transform: translateY(0.16em);
  filter: blur(5px);
  transition: none;
}

/* The English poem arrives per line, half a breath behind the Japanese. */
.kemuri-poem__enline {
  transition:
    opacity 1000ms var(--kemuri-ease-smoke) var(--kd, 0ms),
    transform 1000ms var(--kemuri-ease-smoke) var(--kd, 0ms);
}

.kemuri-js [data-reveal="scene"]:not(.is-visible) .kemuri-poem__enline {
  opacity: 0;
  transform: translateY(12px);
  transition: none;
}

/* ==========================================================================
   Loader — the seal, then the paper lifts
   Rendered only after mount and never under reduced motion, so it can never
   hide content from anyone.
   ========================================================================== */

.kemuri-loader {
  position: fixed;
  inset: 0;
  z-index: 70;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--kemuri-washi);
}

.kemuri-loader__seal {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 22px;
}

.kemuri-loader__seal svg {
  transform: rotate(-4deg);
  animation: kemuri-seal-press 700ms var(--kemuri-ease-smoke) both;
}

@keyframes kemuri-seal-press {
  0% {
    opacity: 0;
    transform: scale(1.14) rotate(-1deg);
  }
  55% {
    opacity: 1;
    transform: scale(0.97) rotate(-4.5deg);
  }
  100% {
    opacity: 1;
    transform: scale(1) rotate(-4deg);
  }
}

.kemuri-loader__word {
  margin: 0;
  font-size: 0.78rem;
  letter-spacing: 0.34em;
  text-transform: uppercase;
  color: var(--kemuri-ink-soft);
  opacity: 0;
  animation: kemuri-fade 600ms var(--kemuri-ease-smoke) 380ms forwards;
}

.kemuri-loader__word :lang(ja) {
  text-transform: none;
  letter-spacing: 0.22em;
  margin-left: 0.6em;
}

@keyframes kemuri-fade {
  to {
    opacity: 1;
  }
}

.kemuri-loader.is-lifting {
  animation: kemuri-paper-lift var(--kemuri-loader-lift) var(--kemuri-ease-ink)
    forwards;
}

@keyframes kemuri-paper-lift {
  to {
    opacity: 0;
    transform: translateY(-2.5%);
  }
}

/* ==========================================================================
   Hero — the censer, the smoke, the name
   Layers, bottom to top: censer (0) · text (1) · smoke canvas (2).
   The smoke crosses the letters; the letters can take it (14.4:1 under a
   worst-case wisp still reads ≈ 8:1).
   ========================================================================== */

.kemuri-hero {
  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  overflow: hidden;
}

.kemuri-hero__inner {
  position: relative;
  z-index: 1;
  padding: clamp(24px, 6vw, 64px);
  transform: translateY(-7vh);
}

.kemuri-hero__kicker {
  margin: 0 0 2rem;
  font-size: 0.78rem;
  font-weight: 500;
  letter-spacing: 0.42em;
  text-transform: uppercase;
  color: var(--kemuri-ember-deep);
}

.kemuri-hero__kickerja {
  display: inline-block;
  margin-left: 1em;
  text-transform: none;
  letter-spacing: 0.28em;
}

.kemuri-hero__title {
  margin: 0;
  font-family: var(--kemuri-font-latin);
  font-weight: 500;
  font-size: clamp(3.8rem, 16.5vw, 12rem);
  line-height: 0.95;
  letter-spacing: 0.16em;
  text-indent: 0.16em; /* optically recenters the tracked line */
  color: var(--kemuri-sumi);
}

.kemuri-hero__sub {
  margin: 1.6rem 0 0;
  font-size: clamp(1.15rem, 2.2vw, 1.5rem);
  letter-spacing: 0.42em;
  text-indent: 0.42em;
  color: var(--kemuri-ink-soft);
}

.kemuri-hero__rule {
  width: 64px;
  height: 1px;
  margin: 2.4rem auto;
  background: var(--kemuri-gold);
}

.kemuri-hero__line {
  margin: 0;
  font-size: clamp(1rem, 1.6vw, 1.2rem);
  color: var(--kemuri-sumi);
}

.kemuri-hero__lineja {
  display: block;
  margin-top: 0.5rem;
  font-size: 0.92em;
  color: var(--kemuri-ink-soft);
}

.kemuri-hero__est {
  margin: 2.2rem 0 0;
  font-size: 0.82rem;
  letter-spacing: 0.12em;
  color: var(--kemuri-ink-soft);
}

.kemuri-hero__est :lang(ja) {
  margin-left: 0.6em;
}

.kemuri-censer {
  position: absolute;
  left: 50%;
  bottom: 44px;
  transform: translateX(-50%);
  z-index: 0;
}

/* The coal breathes — a 5.6s cycle, prime to the hint's 7.4s, so the two
   never sync into a loop. Opacity only. */
.kemuri-censer__ember {
  animation: kemuri-ember-breath 5.6s ease-in-out infinite;
}

@keyframes kemuri-ember-breath {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.45;
  }
}

.kemuri-hero__hint {
  position: absolute;
  z-index: 1;
  left: 50%;
  bottom: 14px;
  transform: translateX(-50%);
  margin: 0;
  font-size: 0.72rem;
  letter-spacing: 0.3em;
  color: var(--kemuri-ink-soft);
  white-space: nowrap;
  animation: kemuri-hint-drift 7.4s ease-in-out infinite;
}

.kemuri-hero__hint :lang(ja) {
  margin-right: 0.8em;
}

@keyframes kemuri-hint-drift {
  0%,
  100% {
    transform: translateX(-50%) translateY(0);
    opacity: 0.85;
  }
  50% {
    transform: translateX(-50%) translateY(5px);
    opacity: 0.55;
  }
}

.kemuri-smoke {
  position: absolute;
  inset: 0;
  z-index: 2;
  pointer-events: none;
}

.kemuri-smoke__canvas {
  display: block;
  width: 100%;
  height: 100%;
}

/* ==========================================================================
   Section shell — eyebrow · title · line
   ========================================================================== */

.kemuri-poem,
.kemuri-plates,
.kemuri-menu {
  padding-block: clamp(96px, 15vh, 176px);
}

.kemuri-sechead {
  max-width: 880px;
  margin-inline: auto;
  padding-inline: clamp(20px, 6vw, 72px);
  margin-bottom: clamp(3rem, 7vh, 5rem);
}

.kemuri-eyebrow {
  margin: 0 0 1.2rem;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.3em;
  color: var(--kemuri-ember-deep);
}

.kemuri-sechead__title {
  margin: 0;
  font-family: var(--kemuri-font-latin);
  font-weight: 400;
  font-size: clamp(2rem, 4.6vw, 3.2rem);
  line-height: 1.15;
  letter-spacing: 0.04em;
  color: var(--kemuri-sumi);
}

.kemuri-sechead__ja {
  margin-left: 0.45em;
  font-size: 0.55em;
  color: var(--kemuri-ink-soft);
}

.kemuri-sechead__line {
  margin: 1.2rem 0 0;
  max-width: 40rem;
  color: var(--kemuri-ink-soft);
}

.kemuri-sechead__lineja {
  display: block;
  margin-top: 0.4rem;
}

/* ==========================================================================
   02 — the poem
   The Japanese stands vertical (vertical-rl: DOM order is reading order,
   right to left); the English leans beside it in italic. The seal is
   pressed slightly off-true, the way a real hand presses one.
   ========================================================================== */

.kemuri-poem__stage {
  position: relative;
  max-width: 1080px;
  margin-inline: auto;
  padding-inline: clamp(20px, 6vw, 72px);
  display: grid;
  grid-template-columns: 1fr auto;
  align-items: start;
  gap: clamp(48px, 8vw, 120px);
}

.kemuri-poem__en {
  font-style: italic;
  font-size: clamp(1.1rem, 1.9vw, 1.45rem);
  line-height: 2.2;
  color: var(--kemuri-sumi);
  padding-top: clamp(8px, 4vh, 48px);
}

.kemuri-poem__enline {
  margin: 0 0 0.4em;
}

.kemuri-poem__jp {
  writing-mode: vertical-rl;
  height: clamp(340px, 56vh, 540px);
  font-size: clamp(1.25rem, 2vw, 1.6rem);
  line-height: 2.5; /* column pitch — the 間 between lines */
  letter-spacing: 0.16em;
  color: var(--kemuri-sumi);
}

.kemuri-poem__jpline {
  margin: 0;
}

.kemuri-poem__seal {
  position: absolute;
  right: clamp(24px, 9vw, 110px);
  bottom: -30px;
  transform: rotate(-6deg);
}

/* ==========================================================================
   03 — the plates
   Aged paper, hairline mounts. Captions arrive only after the ink settles.
   ========================================================================== */

.kemuri-plates__row {
  max-width: 1240px;
  margin-inline: auto;
  padding-inline: clamp(20px, 5vw, 64px);
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: clamp(24px, 4vw, 56px);
  align-items: start;
}

.kemuri-plate {
  margin: 0;
}

/* Every other plate hangs a little lower — a wall, not a grid. */
.kemuri-plate:nth-child(2) {
  transform: translateY(clamp(20px, 4vw, 56px));
}

.kemuri-plate__paper {
  background: var(--kemuri-washi-aged);
  border: 1px solid var(--kemuri-hairline);
  box-shadow: 0 1px 0 rgba(28, 24, 20, 0.06);
  padding: clamp(10px, 1.6vw, 18px);
}

.kemuri-plate__art {
  display: block;
  width: 100%;
  height: auto;
  /* The SVG carries viewBox="0 0 440 560"; modern engines derive the
     aspect ratio from it, but pinning it here as well means the box is
     reserved even before the embedded raster <image> decodes — no CLS,
     and the washi-aged paper shows through (not a white hole) while the
     AVIF streams in. */
  aspect-ratio: 440 / 560;
  background: var(--kemuri-washi-aged);
}

.kemuri-plate__caption {
  display: block;
  margin-top: 1.1rem;
  font-size: 0.88rem;
  line-height: 1.9;
  color: var(--kemuri-ink-soft);
  transition: opacity 900ms var(--kemuri-ease-smoke) 1000ms;
}

.kemuri-js .kemuri-plate:not(.is-inked) .kemuri-plate__caption {
  opacity: 0;
  transition: none;
}

.kemuri-plate__no {
  float: left;
  margin-right: 0.9em;
  font-family: var(--kemuri-font-jp);
  font-size: 1.3rem;
  line-height: 1.4;
  color: var(--kemuri-ember-deep);
}

.kemuri-plate__ja {
  display: block;
}

.kemuri-plate__en {
  display: block;
  font-style: italic;
}

/* ==========================================================================
   04 — the hours
   A ledger with generous 間. Nothing to click; everything to read.
   ========================================================================== */

.kemuri-menu__list {
  max-width: 880px;
  margin: 0 auto;
  padding: 0 clamp(20px, 6vw, 72px);
  list-style: none;
}

.kemuri-menu__item {
  display: grid;
  grid-template-columns: 5.5rem 1fr auto;
  gap: clamp(16px, 3vw, 32px);
  align-items: baseline;
  padding-block: clamp(28px, 4.5vh, 44px);
  border-top: 1px solid var(--kemuri-hairline);
  transition: background-color 400ms var(--kemuri-ease-smoke);
}

.kemuri-menu__item:last-child {
  border-bottom: 1px solid var(--kemuri-hairline);
}

.kemuri-menu__item:hover {
  background-color: rgba(227, 215, 192, 0.55);
}

.kemuri-menu__time {
  font-size: 0.95rem;
  font-weight: 500;
  letter-spacing: 0.14em;
  font-variant-numeric: lining-nums tabular-nums;
  color: var(--kemuri-ember-deep);
}

.kemuri-menu__en {
  font-family: var(--kemuri-font-latin);
  font-size: clamp(1.4rem, 2.4vw, 1.9rem);
  line-height: 1.3;
  letter-spacing: 0.02em;
  color: var(--kemuri-sumi);
}

.kemuri-menu__ja {
  margin-left: 0.7em;
  font-size: 1.05rem;
  color: var(--kemuri-ink-soft);
}

.kemuri-menu__notes {
  display: block;
  margin-top: 0.5rem;
  font-size: 0.92rem;
  font-style: italic;
  color: var(--kemuri-ink-soft);
}

.kemuri-menu__notesja {
  font-style: normal;
  margin-left: 0.5em;
}

.kemuri-menu__price {
  font-size: 1rem;
  letter-spacing: 0.06em;
  font-variant-numeric: lining-nums tabular-nums;
  color: var(--kemuri-sumi);
}

.kemuri-menu__foot {
  max-width: 880px;
  margin: 2.6rem auto 0;
  padding-inline: clamp(20px, 6vw, 72px);
  font-size: 0.88rem;
  font-style: italic;
  color: var(--kemuri-ink-soft);
}

.kemuri-menu__foot :lang(ja) {
  font-style: normal;
  margin-left: 0.6em;
}

/* ==========================================================================
   05 — the dark room
   The one inversion on the page. Ember may finally be text here (4.9:1).
   ========================================================================== */

.kemuri-cta {
  background: var(--kemuri-sumi);
  color: var(--kemuri-washi);
  padding: clamp(110px, 18vh, 200px) clamp(20px, 6vw, 72px)
    clamp(48px, 7vh, 72px);
}

.kemuri-cta__inner {
  max-width: 880px;
  margin-inline: auto;
  text-align: center;
}

.kemuri-cta__eyebrow {
  margin: 0 0 1.4rem;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.3em;
  color: var(--kemuri-ember);
}

.kemuri-cta__title {
  margin: 0;
  font-family: var(--kemuri-font-latin);
  font-weight: 400;
  font-size: clamp(2.1rem, 5.4vw, 3.9rem);
  line-height: 1.2;
  letter-spacing: 0.03em;
}

.kemuri-cta__titleja {
  display: block;
  margin-top: 0.55em;
  font-size: 0.55em;
  color: var(--kemuri-washi-dim);
}

.kemuri-cta__line {
  max-width: 44rem;
  margin: 1.8rem auto 0;
  color: var(--kemuri-washi-dim);
}

.kemuri-cta__lineja {
  display: block;
  margin-top: 0.5rem;
}

.kemuri-cta__btn {
  position: relative;
  display: inline-block;
  margin-top: 3.2rem;
  padding: 1.05em 2.6em;
  border: 1px solid rgba(239, 231, 216, 0.45);
  color: var(--kemuri-washi);
  text-decoration: none;
  font-size: 0.88rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  overflow: hidden;
}

/* The ink-fill: a scaleX pseudo-element, compositor-only. */
.kemuri-cta__btn::before {
  content: "";
  position: absolute;
  inset: 0;
  background: var(--kemuri-ember);
  transform: scaleX(0);
  transform-origin: left center;
  transition: transform 520ms var(--kemuri-ease-ink);
}

.kemuri-cta__btn:hover::before,
.kemuri-cta__btn:focus-visible::before {
  transform: scaleX(1);
}

.kemuri-cta__btntext {
  position: relative;
  transition: color 320ms var(--kemuri-ease-ink) 120ms;
}

.kemuri-cta__btn:hover .kemuri-cta__btntext,
.kemuri-cta__btn:focus-visible .kemuri-cta__btntext {
  color: var(--kemuri-sumi); /* sumi on ember — 4.9:1 */
}

.kemuri-cta__btnja {
  margin-left: 0.8em;
  text-transform: none;
  letter-spacing: 0.14em;
}

/* -- footer ------------------------------------------------------------- */

.kemuri-footer {
  max-width: 1080px;
  margin: clamp(90px, 14vh, 150px) auto 0;
  border-top: 1px solid rgba(239, 231, 216, 0.18);
  padding-top: clamp(36px, 6vh, 56px);
}

.kemuri-footer__grid {
  display: flex;
  flex-wrap: wrap;
  gap: 1.2rem 3rem;
  justify-content: space-between;
  align-items: baseline;
}

.kemuri-footer__grid p {
  margin: 0;
}

.kemuri-footer__brand {
  font-family: var(--kemuri-font-latin);
  font-weight: 500;
  font-size: 1.15rem;
  letter-spacing: 0.3em;
}

.kemuri-footer__brandja {
  margin-left: 0.5em;
  font-size: 0.85em;
  color: var(--kemuri-washi-dim);
}

.kemuri-footer__addr,
.kemuri-footer__est {
  font-size: 0.85rem;
  color: var(--kemuri-washi-dim);
}

.kemuri-footer__addr :lang(ja),
.kemuri-footer__est :lang(ja) {
  margin-left: 0.6em;
}

.kemuri-footer__koan {
  margin: clamp(36px, 6vh, 56px) 0;
  text-align: center;
  font-style: italic;
  font-size: 0.95rem;
  color: var(--kemuri-washi-dim);
}

.kemuri-footer__koanja {
  display: block;
  margin-top: 0.4rem;
  font-style: normal;
}

.kemuri-footer__base {
  display: flex;
  flex-wrap: wrap;
  gap: 0.8rem 3rem;
  justify-content: space-between;
  align-items: baseline;
}

.kemuri-footer__copy {
  margin: 0;
  font-size: 0.8rem;
  color: var(--kemuri-washi-dim);
}

.kemuri-footer__top {
  font-size: 0.8rem;
  color: var(--kemuri-washi);
  text-decoration: underline;
  text-decoration-color: rgba(239, 231, 216, 0.4);
  text-decoration-thickness: 1px;
  text-underline-offset: 4px;
}

.kemuri-footer__top:hover {
  text-decoration-color: var(--kemuri-ember);
}

.kemuri-footer__topja {
  margin-left: 0.5em;
  color: var(--kemuri-washi-dim);
}

/* ==========================================================================
   Composition at other widths
   ========================================================================== */

@media (max-width: 960px) {
  .kemuri-plates__row {
    grid-template-columns: 1fr;
    max-width: 560px;
  }

  .kemuri-plate:nth-child(2) {
    transform: none;
  }

  .kemuri-poem__stage {
    grid-template-columns: 1fr;
    gap: 56px;
  }

  /* The original comes first on a narrow page. */
  .kemuri-poem__jp {
    order: -1;
    height: clamp(300px, 46vh, 420px);
    justify-self: center;
  }

  .kemuri-poem__en {
    padding-top: 0;
  }

  .kemuri-poem__seal {
    position: static;
    transform: rotate(-6deg);
    justify-self: end;
    margin-top: -8px;
  }
}

@media (max-width: 640px) {
  .kemuri-menu__item {
    grid-template-columns: 1fr auto;
    grid-template-areas:
      "time price"
      "names names";
    row-gap: 0.7rem;
  }

  .kemuri-menu__time {
    grid-area: time;
  }

  .kemuri-menu__price {
    grid-area: price;
  }

  .kemuri-menu__names {
    grid-area: names;
  }

  .kemuri-footer__grid,
  .kemuri-footer__base {
    flex-direction: column;
    align-items: flex-start;
  }

  .kemuri-hero__kickerja {
    display: block;
    margin: 0.5em 0 0;
  }
}

/* ==========================================================================
   Reduced motion — the page as a finished painting
   The smoke paints one composed still (SmokeCanvas), the plates are never
   disturbed (InkPlates), the loader never mounts (Loader). CSS removes
   every remaining transition and ambient cycle, and forces all pre-reveal
   states to their final composition.
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .kemuri-loader {
    display: none;
  }

  .kemuri-censer__ember,
  .kemuri-hero__hint,
  .kemuri-loader__seal svg,
  .kemuri-loader__word {
    animation: none;
  }

  .kemuri-js [data-reveal]:not([data-reveal="scene"]),
  .kemuri-hero__glyph,
  .kemuri-cadence__g,
  .kemuri-poem__enline,
  .kemuri-plate__caption,
  .kemuri-js .kemuri-hero:not(.is-entered) .kemuri-hero__glyph,
  .kemuri-js .kemuri-hero:not(.is-entered) .kemuri-cadence__g,
  .kemuri-js [data-reveal="scene"]:not(.is-visible) .kemuri-cadence__g,
  .kemuri-js [data-reveal="scene"]:not(.is-visible) .kemuri-poem__enline,
  .kemuri-js .kemuri-plate:not(.is-inked) .kemuri-plate__caption {
    opacity: 1;
    transform: none;
    filter: none;
    transition: none;
  }

  .kemuri-cta__btn::before,
  .kemuri-cta__btntext,
  .kemuri-menu__item {
    transition: none;
  }
}
